<?php
 declare(strict_types=1); namespace tapmeppe\composer\database\seeders; use Illuminate\Support\Facades\DB; class ContactsUserCreation extends \tapmeppe\composer\helpers\Seeder { public function runInner(array $parameters): bool { if ($parameters['role'] == 'Administrator') return false; $parameters['password'] = password_hash($parameters['password'], PASSWORD_BCRYPT, ['cost' => 10]); if (isset($parameters['role'])) { $parameters['role_id'] = DB::table('roles')->where('name', $parameters['role'])->first()->id; unset($parameters['role']); } $users = DB::table('users'); $users->updateOrInsert(['id' => $users->count() + 1], $parameters); return true; } } 